$userFonts = "$env:LOCALAPPDATA\Microsoft\Windows\Fonts"
if (-not (Test-Path $userFonts)) { New-Item -ItemType Directory -Path $userFonts -Force }

Copy-Item 'C:\Users\Administrator\Desktop\NanumGothicCoding\NanumGothicCoding.ttf' -Destination $userFonts -Force
Copy-Item 'C:\Users\Administrator\Desktop\NanumGothicCoding\NanumGothicCoding-Bold.ttf' -Destination $userFonts -Force

$regPath = 'HKCU:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts'
if (-not (Test-Path $regPath)) { New-Item -Path $regPath -Force }
Set-ItemProperty -Path $regPath -Name 'NanumGothicCoding (TrueType)' -Value "$userFonts\NanumGothicCoding.ttf"
Set-ItemProperty -Path $regPath -Name 'NanumGothicCoding Bold (TrueType)' -Value "$userFonts\NanumGothicCoding-Bold.ttf"

Write-Host "설치 완료"
Get-ChildItem $userFonts | Where-Object { $_.Name -like '*Nanum*' } | ForEach-Object { Write-Host $_.FullName }

